 function compareTextsPanel(q){
  const normalize=(source,fallbackTitle,fallbackText)=>{
    if(typeof source==='string')return {title:fallbackTitle,text:source,details:[]};
    return source||{title:fallbackTitle,text:fallbackText,details:[]};
  };
  const a=normalize(q.source_a||q.text_a||q.passage_a,'Source A',q.passage||q.text||'Read the first source.');
  const b=normalize(q.source_b||q.text_b||q.passage_b,'Source B',q.related_passage||'Read the second source.');
  const details=(source)=>Array.isArray(source.details)?source.details:(Array.isArray(source.key_details)?source.key_details:[]);
  const detailList=(items)=>items.length?`<ul>${items.slice(0,4).map((item)=>`<li>${esc(item)}</li>`).join('')}</ul>`:'<p class="empty-detail">Add details from this source.</p>';
  const shared=q.shared_topic||q.topic||q.title||'Shared topic';
  const prompts=q.compare_prompts||['What information appears in both sources?','What is unique to each source?'];
  const synth=q.synthesis_guidance||q.synthesis||q.correct_answer||'Use details from both sources to write one accurate answer.';
  return `<div class="visual-model skill-visual-inner compare-texts-panel-visual" data-renderer="compare_texts_panel"><h4>Compare sources: ${esc(shared)}</h4><div class="compare-texts-grid"><article class="compare-text-source source-a"><header><span>Source A</span><strong>${esc(a.title||'Source A')}</strong></header><p>${esc(a.text||'')}</p><div class="source-details"><b>Key details</b>${detailList(details(a))}</div></article><article class="compare-text-source source-b"><header><span>Source B</span><strong>${esc(b.title||'Source B')}</strong></header><p>${esc(b.text||'')}</p><div class="source-details"><b>Key details</b>${detailList(details(b))}</div></article></div><div class="compare-texts-synthesis"><div class="shared-topic"><b>Shared topic:</b> ${esc(shared)}</div><div class="compare-prompts">${prompts.slice(0,3).map((p)=>`<span>${esc(p)}</span>`).join('')}</div><p><b>Synthesize:</b> ${esc(synth)}</p></div><p class="sw-visual-caption">Compare what both sources say, notice unique details, then integrate information accurately.</p></div>`;
 }

